  import sailpoint.object.Capability;
  import sailpoint.object.Identity;
  import sailpoint.object.Identity.CapabilityManager;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Bundle;
  import sailpoint.object.Filter;

  import sailpoint.tools.Util;

  String logPrefix = "CNC_RME_GetWorkgroupMembers:";

  //String loggedInUser = "spadmin";
  //String workgroupId = "c0a8019a7fd2158a817fd335b6f302e5"; 

  public void log(String message) {    
    log.error(logPrefix+" "+message);
  }


  log("loggedInUser "+loggedInUser);


  Map returnMap = new HashMap();

  List headers =  new ArrayList();

  Map map1 = new HashMap();
  map1.put("label", "Name");
  map1.put("key", "name");
  headers.add(map1);

   Map map2 = new HashMap();
  map2.put("label", "NetworkId");
  map2.put("key", "employeeid");
  headers.add(map2);

  Map map3 = new HashMap();
  map3.put("label", "Display Name");
  map3.put("key", "displayName");
  headers.add(map3);

  Map map4 = new HashMap();
  map4.put("label", "Status");
  map4.put("key", "status");
  headers.add(map4);

  returnMap.put("headers",headers);

  List members = new ArrayList();
		Identity workgroup = context.getObjectById(Identity.class, workgroupId);
		if (workgroup != null && workgroup.isWorkgroup()) {
			QueryOptions qo = new QueryOptions();
			qo.addFilter(Filter.eq("workgroups.id", workgroupId));
			qo.addFilter(Filter.eq("workgroup", false));
			qo.setOrderBy("name");
			qo.setOrderAscending(true);
			Iterator itr = context.search(Identity.class, qo);
			if (itr != null) {
				while(itr.hasNext()) {
					Identity member = (Identity)itr.next();
					Map row = new HashMap();
					row.put("name", member.getName());
					row.put("displayName", member.getDisplayableName());
					Object employeeId = member.getAttribute("employeeid");
					row.put("employeeid", employeeId != null ? employeeId.toString() : "");
					row.put("status", member.isInactive() ? "Inactive" : "Active");
					members.add(row);
				}
				Util.flushIterator(itr);
			}
		}
		else if (workgroup != null) {
			Map member = new HashMap();
			member.put("name",workgroup.getName());
			member.put("displayName",workgroup.getDisplayableName());
			member.put("employeeid",workgroup.getAttribute("employeeid"));
			member.put("status", workgroup.isInactive() ? "Inactive" : "Active");
			members.add(member);
		}

  returnMap.put("objects",members);
  log("Exit getWorkgroupMembers");
  return returnMap;
